SELECT (COUNT(?nom) AS ?count) WHERE {
  ?producer rdfs:label ?label ;
      wdt:P31 wd:Q568.
  FILTER (CONTAINS(STR(LCASE(?label)), "palmasi"))

  ?song wdt:P125 ?producer ;
        wdt:P179 wd:Q1108392.

  ?song wdt:P175 ?artist.

  ?artist wdt:P1727 ?nom.
}

